INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04510', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於變遷中現代家庭定義的敘述，下列何者錯誤？', '["對於現實世界越來越難持有共通的觀念，因此傳統家庭的階級與權力結構的概念，逐漸不適用 於現代家庭", "Gergen（1991）認為縱使家庭很容易成為衝突的場域，但後現代的家庭仍然能夠提供情感性的 支持，使家庭成員能夠適應飽和性社會", "人們被電子媒體傳播圍繞，導致越來越多人發現自己很難找到值得相信的事物，人們對世界與 自我的不確定感，此為Gergen（1991）所意指的「社會性飽和」（socialsaturation）概念", "Gergen（1991）認為「飽和家庭」（saturatedfamily）的概念是指家庭關係的不確定和不定型， 長期處於不斷變動的狀態，缺乏界線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04511', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所謂「家庭團體決策」（family-group decision-making）或稱「家庭團體會議」（family-group conferencing）的概念是將家庭的參與納入兒童保護的一環，此模式是近年來因應兒童虐待與疏忽 的重要策略。以下對於家庭團體決策模式的敘述，何者較不恰當？', '["邀請家庭成員和專業人士一起開會，共同討論兒童福利系統中需要關照的兒童照顧需求和因應 方式", "家庭團體決策是以家庭為中心、優勢觀點取向、和文化及社區為基礎的服務模式", "雖說家庭擁有最多的資訊，但此模式理解有些家庭解決問題的能力有限，因此鼓勵家庭在兒童 照顧與保護的最後決定以專業人士為主", "此模式鼓勵家庭和其他家庭以及所處的社區建立支持網絡，共同解決問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04512', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是Amato（2000）認為男女雙方面對離婚時的主要課題？', '["重新定義自己是單身的個體", "為了他人犧牲自我", "重新找到和前配偶相處的方式", "對於探索新的關係會有不確定感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04513', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所謂混合家庭（blendedfamily）或是繼親家庭（stepfamily）：係指離婚後，兩個單親家庭透過再 婚而組成的家庭類型。對於混合家庭或繼親家庭的敘述，下列何者正確？', '["家庭的變動對繼親家庭的孩子所產生的影響，青少年的調適會比年幼的孩子還更能接受家庭成員", "為了協助孩子適應家庭的變遷，由繼父、母扮演主要管教角色，較有助於孩子與繼父、母的互動", "繼親家庭面對家庭的變動，婚姻關係經營是婚姻品質上最優先的因應策略", "儘量避免無監護權的父母探望孩子，降低孩子無法接受家庭關係變動的情況"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04514', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類行為與社會環境中「社會面向」的敘述，下列何者正確？', '["社會面向是人與個體或在群體中互動所形成的關係系統", "社會面向包含消化、呼吸、泌尿、生殖、運動與神經等項", "社會面向主要來自個人期待、動機和誘因的自我建構", "社會面向既塑造又限制人類的行為而且無法改變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04515', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關功能論（functionalism）與社會功能（socialfunctioning）的敘述，下列何者正確？', '["功能論主張社會是人與人間彼此互動後意義建構的產物", "社會功能是研究個人與社會變遷之間關係的研究方法", "功能論特別強調人們彼此互惠、互利的理性行為模式", "社會功能重視人與環境互動完成日常生活所需任務及角色的能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04516', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老人退休後考量自己能提供的資源或籌碼變少，進而有意減少人際間的互動。以上敘述較符合下 列那項觀點？', '["老人活動論", "社會衝突論", "符號互動論", "社會交換論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04517', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生態系統論的敘述，下列何者錯誤？', '["它是門研究有機體之間和有機體與環境之間互動關係的科學", "整體等於部份總合的化約論（reductionism）是其重要原則", "它看重人與情境和系統與環境的雙重焦點", "社會工作實務發生在人類系統與其環境間相交的介面及其交互影響的方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04518', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關女性主義的敘述，下列何者正確？', '["它屬於一種本質論（essentialism）的觀點", "它主張性別是個人經驗的全部", "它認為社會現實是由男性觀點所建構", "它主張性別是絕對而且自然的生理事實"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04519', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關亞培格量表（Apgarscore）的敘述，下列何者錯誤？', '["由Apgar醫師所發展出來的", "由五項（脈搏、呼吸、睡眠、外觀、臉相）指標評估新生兒對子宮外的生活適應", "出生後第一分鐘的得分，可評估新生兒的生存機率", "新生兒心跳速率每分鐘少於100次得1分，每分鐘多於100次得2分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "587b798b6435", "answer_pdf_sha1": "dcb8aa0b40fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
